        },
        "errors": "no"
    },
    {
        "lineno": "66",
        "command": "FUNCTION",
        "parser_kind": "LLM",
        "payload": {
            "kind": "function",
            "sys_name": "G2",
            "params": [],
            "body": "0.0"
        },
        "errors": "no"
    }
]

