mcl2mid_json_dict.PORT:
PORT命令在MCL中用于定义端口，以及端口对应的几何位置、端口参数等等，对应中间符号中的port, field_excitation元素，互相之间以port_no为关联键
PORT命令对应的json项的json模式为：
外部激励，即'direction' = 'POSITIVE':
{
    "port":[{
        "PORT_type": "INPUTMURPORT",
        "sys_no": "{cmd_no}",
        "parameters": {
          "PORT_type": "INPUTMURPORT",
          "kind": "MurVoltagePort",
          "geom_name": "XXXX",
          "geom_value": [[0.0,Y1,Z1],[0.0,Y2,Z2]],
          "direction": "POSITIVE",
          "norm_type": "VOLTAGE",
          "norm_geom_name": "INLET",
          "norm_geom_value": [[0.0,Y1,Z1],[0.0,Y2,Z2]]
        },
        "dependencies": [],
        "cac_result": {}
      }
    ],
    "field_excitation":[{
        "port_no": "{cmd_no}",
        "parameters": {
            "incoming_func_body": "VOLTAGE_MAX*max(0.0,min(1.0,t/TRISE))",
            "incoming_func_vars": [
                {"VOLTAGE_MAX": "500000"},
                {"TRISE": "1e-9"}
            ],
            "incoming_opt": {
                "E2": "G1",
                "E3": "G2"
            }
        },
        "dependencies": [
            {"G1": "[FUNCTION value] G1 ( Z , R )  = 1 / R"},
            {"G2": "[FUNCTION value] G2 = 0.0"}
        ],
        "cac_result": {}
    }]
}
开放端口，即'direction' = 'NEGATIVE':
{
    "port":[{
        "PORT_type": "OPENPORT",
        "parameters": {
          "PORT_type": "OPENPORT",
          "kind": "OPENPORT",
          "geom_name": "XXXX",
          "geom_value": [[0.0,Y1,Z1],[0.0,Y2,Z2]],
          "direction": "NEGATIVE"
        },
        "cac_result": {},
        "dependencies": []
    }],
    "field_excitation":[]
}

### 示例输入：
[
    {
        "kind": "PORT",
        "geom_name": "LINE_IN",
        "direction": "POSITIVE",
        "options": [
            {
                "port_opt_name": "INCOMING",
                "incoming_func": "FIN",
                "incoming_opt": [
                    "E2",
                    "G1",
                    "E3",
                    "G2"
                ]
            },
            {
                "port_opt_name": "NORMALIZATION",
                "norm_type": "VOLTAGE",
                "geom_type": "line",
                "peak_value": [
                    "LINE_IN"
                ]
            }
        ],
        "cmd_no": 1,
        "dependency": [
            {
                "VOLTAGE.MAX": "600000"
            },
            {
                "TRISE": "1e-9"
            },
            {
                "sys_name": "FIN",
                "command": "FUNCTION",
                "text": "FUNCTION FIN ( T )  = VOLTAGE.MAX * MAX ( 0.0 , MIN ( 1.0 , T / TRISE )  )  ;"
            },
            {
                "sys_name": "G1",
                "command": "FUNCTION",
                "text": "FUNCTION G1 ( Z , R )  = 1 / R ;"
            },
            {
                "sys_name": "G2",
                "command": "FUNCTION",
                "text": "FUNCTION G2 = 0.0 ;"
            },
            {
                "LINE_IN": "[line value] [(5.0, 10.0), (5.0, 25.0)] (mm)"
            }
        ]
    },
    {
        "kind": "PORT",
        "geom_name": "LINE_OUT",
        "direction": "NEGATIVE",
        "options": [],
        "cmd_no": 2,
        "dependency": [
            {
                "LINE_OUT": "[line value] [(600.0, 0.0), (600.0, 25.0)] (mm)"
            }
        ]
    }
]
### 示例输出：
{
