mcl2mid_json_dict.PRESET:
PRESET命令在MCL中用于定义静电磁场，对应中间符号中的electromagnetic_field元素，
PRESET命令对应的json项的json模式为：
{"sys_name": "XXXX", "component": "0/1/2", "func_name": "YYYY", "kind": "zrFunc"}

### 示例输入：
[
    {
        "kind": "preset",
        "preset_name": "B1ST",
        "func_name": "B_Z",
        "cmd_no": 1,
        "dependency": [
            {
                "sys_name": "B_Z",
                "command": "FUNCTION",
                "text": "FUNCTION B_Z ( Z , R )   =  2.8 /  ( 1 + EXP (  ( Z - 0.29 )  / 0.02 )  )    ;"
            }
        ]
    },
    {
        "kind": "preset",
        "preset_name": "B2ST",
        "func_name": "B_R",
        "cmd_no": 2,
        "dependency": [
            {
                "sys_name": "B_R",
                "command": "FUNCTION",
                "text": "FUNCTION B_R ( Z , R )   =  2.8 /  ( 2 * 0.02 )  * R * EXP (  ( Z - 0.29 )  / 0.02 )  /  (  ( 1 + EXP (  ( Z - 0.29 )  / 0.02 )  )  ** 2 )   ;"
            }
        ]
    }
]
### 示例输出：
{
    "electromagnetic_field": [
        {
            "sys_name": "B1ST",
            "parameters": {
                "component": "0",
                "func_name": "B_Z",
                "kind": "zrFunc"
            },
            "cac_result": {
                "func_body": "2.8/(1+exp((z-0.29)/0.02))",
                "func_vars": {}
            }
        },
        {
            "sys_name": "B2ST",
            "parameters": {
                "component": "1",
                "func_name": "B_R",
                "kind": "zrFunc"
            },
            "cac_result": {
                "func_body": "2.8/(2*0.02)*r*exp((z-0.29)/0.02)/((1+exp((z-0.29)/0.02))^2)",
                "func_vars": {}
            }
        }
    ]
}

